#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
int n;
string s; 
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>s;
	s=" "+s;
	int i=1,j=2,k=0;
	while(i<=n&&j<=n&&k<n)
	{
		if(s[(i+k-1)%n+1]==s[(j+k-1)%n+1]) k++;
		else
		{
			if(s[(i+k-1)%n+1]>s[(j+k-1)%n+1]) i+=(k+1);
			else j+=(k+1);
			if(i==j) i++;
			k=0;
		}
	}
	for(int ii=1;ii<=n;ii++)
	{
		cout<<s[(min(i,j)+ii-2)%n+1];
	}
	return 0;
}
